HOC - это функция, которая принимает компонент и возвращает новый компонент с дополнительной логикой.

```javascript
function withLogger(WrappedComponent) {
  return function EnhancedComponent(props) {
    console.log('Props:', props);
    return <WrappedComponent {...props} />;
  };
}

// Использование
const EnhancedButton = withLogger(Button);
```

В неуправляемых компонентах двустороннее связывание реализуется через refs:

```javascript
function UncontrolledForm() {
  const inputRef = useRef();

  const handleSubmit = (e) => {
    e.preventDefault();
    // Чтение значения из DOM
    console.log(inputRef.current.value);
  };

  const updateValue = (newValue) => {
    // Установка значения в DOM
    inputRef.current.value = newValue;
  };

  return (
    <form onSubmit={handleSubmit}>
      <input ref={inputRef} type="text" />
      <button type="submit">Отправить</button>
    </form>
  );
}
```

Context API - это способ передачи данных через дерево компонентов без проп-дриллинга. Используется для:
- Темизации
- Аутентификации
- Локализации
- Общего состояния приложения

```javascript
const ThemeContext = createContext();

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <ChildComponent />
    </ThemeContext.Provider>
  );
}
```
